-- 008: Biblioteca de ejercicios UNIFICADA (fuente unica para app + bot)
-- Fusiona: biblioteca_ejercicios (app) + mapa de GIFs (cerebro) + libreria del bot (cues/errores/red flags)
-- Correr en el SQL Editor de Supabase. Idempotente (se puede correr dos veces).

ALTER TABLE biblioteca_ejercicios
  ADD COLUMN IF NOT EXISTS gif text DEFAULT '',
  ADD COLUMN IF NOT EXISTS musculo text DEFAULT '',
  ADD COLUMN IF NOT EXISTS secundarios jsonb DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS instrucciones jsonb DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS cues jsonb DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS errores jsonb DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS red_flags jsonb DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS regresion text DEFAULT '',
  ADD COLUMN IF NOT EXISTS progresion text DEFAULT '',
  ADD COLUMN IF NOT EXISTS fuente_gif text DEFAULT '';

UPDATE biblioteca_ejercicios SET cues = '["Empujá desde los talones."]'::jsonb, errores = '["Arquear la espalda", "Subir rápido", "No activar glúteos"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Sin peso', progresion = 'Con carga, corebag, aparato o barra' WHERE lower(nombre) = lower('Puente de gluteos');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-un-brazo-banda.gif', musculo = 'biceps', secundarios = '["biceps", "shoulders"]'::jsonb, instrucciones = '["Sujeta la banda a un punto de anclaje estable a la altura de la cintura.", "Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros.", "Sostén la banda con una mano, con la palma hacia adentro, y da un paso atrás para generar tensión en la banda.", "Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta.", "Tira de la banda hacia la cintura, juntando los omóplatos.", "Haz una pausa por un momento en la parte superior del movimiento, luego suelta lentamente la banda de vuelta a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo a un brazo (banda)');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/jalon-brazos-estirados.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Sujeta la banda a un punto de anclaje alto, como una barra de dominadas o una viga resistente.", "Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros.", "Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros.", "Extiende completamente los brazos por encima de la cabeza, manteniendo los codos ligeramente flexionados.", "Activa los dorsales y tira de la banda hacia abajo en dirección al pecho, juntando los omóplatos.", "Haz una pausa breve en la parte baja del movimiento, luego libera lentamente la tensión y vuelve a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Jalon brazos estirados (banda)');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/rotacion-externa-banda.gif', musculo = 'rotator cuff', secundarios = '["rotator cuff", "trapezius"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas.", "Sujeta el mango del cable con el brazo extendido frente a ti, paralelo al suelo.", "Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás.", "Rota lentamente el brazo hacia afuera, alejándolo de tu cuerpo, manteniendo el codo en la misma posición.", "Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Rotacion externa (banda)');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/press-pallof.gif', musculo = 'obliques', secundarios = '["obliques", "glutes"]'::jsonb, instrucciones = '["Sujeta la banda a un punto de anclaje resistente a la altura de la cintura.", "Ponte de pie perpendicular al punto de anclaje con los pies separados a la altura de los hombros.", "Agarra la agarradera de la banda con ambas manos y aléjate del punto de anclaje para generar tensión en la banda.", "Lleva las manos hacia el pecho, manteniendo los codos flexionados y cerca del cuerpo.", "Activa el core y mantén una postura estable.", "Extiende los brazos rectos frente a ti, empujando la banda alejándola del cuerpo.", "Mantén la posición extendida durante unos segundos, enfocándote en mantener la tensión en el core.", "Lleva lentamente las manos de vuelta al pecho, resistiendo el tirón de la banda.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Press Paloff (banda)');
UPDATE biblioteca_ejercicios SET cues = '["Codo pegado al cuerpo."]'::jsonb, errores = '["Separar el codo", "Girar el torso", "Ir rápido"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Menos tensión', progresion = 'Más tensión' WHERE lower(nombre) = lower('Rotacion interna con banda');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-banda.gif', musculo = 'trapezius', secundarios = '["trapezius", "rhomboids", "biceps"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies.", "Sostén las agarraderas de la banda con las palmas mirándose entre sí y los brazos extendidos frente a ti.", "Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta.", "Tira de la banda hacia el pecho, juntando los omóplatos.", "Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión y regresa a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo con banda');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/jalon-banda-arriba.gif', musculo = 'biceps', secundarios = '["biceps", "rhomboids", "rear deltoids"]'::jsonb, instrucciones = '["Sujeta la banda a un punto de anclaje resistente por encima de tu cabeza.", "Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros.", "Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros.", "Da un paso atrás para generar tensión en la banda, manteniendo los brazos completamente extendidos.", "Activa el core y junta los omóplatos.", "Tira de la banda hacia el pecho, guiando el movimiento con los codos.", "Haz una pausa por un momento en la parte inferior del movimiento, sintiendo la contracción en los dorsales.", "Suelta lentamente la tensión de la banda y regresa a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Jalon con banda desde arriba');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/buenos-dias.gif', musculo = 'lower back', secundarios = '["lower back"]'::jsonb, instrucciones = '["Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda.", "Manteniendo la espalda recta y el core activado, flexiona las caderas hacia delante, empujando los glúteos hacia atrás como si intentaras tocar la pared detrás de ti con ellos.", "Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales.", "Haz una pausa breve y luego vuelve a la posición inicial apretando los glúteos y empujando las caderas hacia delante.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Cadera atrás."]'::jsonb, errores = '["Redondear la espalda", "Flexionar mucho las rodillas", "Bajar rápido"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Sin peso', progresion = 'Más carga' WHERE lower(nombre) = lower('Buenos dias con disco');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/jalon-mancuerna.gif', musculo = 'latissimus dorsi', secundarios = '["latissimus dorsi", "triceps"]'::jsonb, instrucciones = '["Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo.", "Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho.", "Manteniendo una ligera flexión en los codos, baja lentamente la mancuerna detrás de la cabeza hasta sentir un estiramiento en el pecho y los hombros.", "Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Jalon con mancuerna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-inclinado-peso.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo.", "Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado.", "Deja que los brazos cuelguen rectos hacia el suelo, con los codos ligeramente flexionados.", "Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí.", "Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Espalda firme."]'::jsonb, errores = '["Redondear la espalda", "Tirar con los brazos", "Levantar los hombros"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Menos peso', progresion = 'Más carga' WHERE lower(nombre) = lower('Remo con disco');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/peso-muerto-una-pierna.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha.", "Traslada tu peso a la pierna izquierda y levanta el pie derecho ligeramente del suelo.", "Manteniendo la espalda recta, inclínate hacia adelante desde las caderas y baja la mancuerna hacia el suelo.", "Al mismo tiempo, extiende la pierna derecha recta hacia atrás, manteniendo una ligera flexión en la rodilla izquierda.", "Baja la mancuerna hasta que tu torso y tu pierna derecha queden paralelos al suelo.", "Haz una pausa por un momento, luego activa los glúteos y los isquiotibiales para volver a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Peso muerto a una pierna sin peso');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/sentadilla-bulgara.gif', musculo = 'glutes', secundarios = '["glutes", "hamstrings", "calves"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano.", "Da un paso hacia adelante con un pie y coloca los pies de modo que el pie delantero quede plano en el suelo y el pie trasero quede elevado sobre un banco o escalón.", "Baja el cuerpo flexionando la rodilla y la cadera delanteras, manteniendo la rodilla trasera ligeramente flexionada y el talón trasero levantado del suelo.", "Continúa bajando hasta que el muslo delantero quede paralelo al suelo, luego empuja con el talón delantero para volver a la posición inicial.", "Repite el número de repeticiones deseado y luego cambia de pierna y repite."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Sentadilla bulgara sin peso');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/vuelta-al-mundo.gif', musculo = 'triceps', secundarios = '["triceps", "forearms"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano.", "Extiende los brazos rectos hacia los lados a la altura de los hombros, con las palmas hacia abajo.", "Manteniendo los brazos rectos, gira lentamente los brazos en un movimiento circular, llevando las mancuernas frente al cuerpo y luego por encima de la cabeza.", "Continúa el movimiento circular, bajando las mancuernas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Mové lento."]'::jsonb, errores = '["Arquear la espalda", "Ir rápido", "Subir los hombros"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Menos peso', progresion = 'Más peso' WHERE lower(nombre) = lower('Vuelta al mundo con disco');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/press-arriba.gif', musculo = 'triceps', secundarios = '["triceps", "upper back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adelante.", "Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza.", "Haz una pausa por un momento en la parte superior, luego baja lentamente las mancuernas de vuelta a la altura de los hombros.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Press arriba con disco');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/buenos-dias.gif', musculo = 'lower back', secundarios = '["lower back"]'::jsonb, instrucciones = '["Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda.", "Manteniendo la espalda recta y el core activado, flexiona las caderas hacia delante, empujando los glúteos hacia atrás como si intentaras tocar la pared detrás de ti con ellos.", "Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales.", "Haz una pausa breve y luego vuelve a la posición inicial apretando los glúteos y empujando las caderas hacia delante.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Buenos dias con mancuerna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-inclinado-peso.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo.", "Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado.", "Deja que los brazos cuelguen rectos hacia el suelo, con los codos ligeramente flexionados.", "Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí.", "Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo con mancuerna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/peso-muerto-una-pierna.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha.", "Traslada tu peso a la pierna izquierda y levanta el pie derecho ligeramente del suelo.", "Manteniendo la espalda recta, inclínate hacia adelante desde las caderas y baja la mancuerna hacia el suelo.", "Al mismo tiempo, extiende la pierna derecha recta hacia atrás, manteniendo una ligera flexión en la rodilla izquierda.", "Baja la mancuerna hasta que tu torso y tu pierna derecha queden paralelos al suelo.", "Haz una pausa por un momento, luego activa los glúteos y los isquiotibiales para volver a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Peso muerto a 1 pierna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/press-hombros-sentado.gif', musculo = 'triceps', secundarios = '["triceps", "upper back"]'::jsonb, instrucciones = '["Siéntate en un banco con una mancuerna en cada mano, apoyadas en los muslos.", "Sube las mancuernas hasta la altura de los hombros, con las palmas hacia adelante.", "Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza.", "Haz una pausa por un momento en la parte superior, luego baja lentamente las mancuernas de vuelta a la altura de los hombros.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Press de hombros sentado con mancuernas');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/sentarse-pararse-cajon.gif', musculo = 'glutes', secundarios = '["glutes", "hamstrings", "calves"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna verticalmente contra el pecho con ambas manos.", "Manteniendo el pecho erguido y el core activado, baja el cuerpo a una posición de sentadilla empujando las caderas hacia atrás y flexionando las rodillas.", "Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente.", "Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Sentarse y pararse del cajon con peso al pecho');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/press-pecho-barra.gif', musculo = 'triceps', secundarios = '["triceps", "shoulders"]'::jsonb, instrucciones = '["Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco.", "Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros.", "Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos.", "Baja la barra lentamente hacia el pecho, manteniendo los codos pegados al cuerpo.", "Haz una pausa breve cuando la barra toque el pecho.", "Empuja la barra de vuelta a la posición inicial extendiendo los brazos.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Press de pecho con barra en banco plano');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/peso-muerto-kettlebell.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono.", "Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo que las rodillas se flexionen ligeramente.", "Baja las mancuernas hasta sentir un estiramiento en los isquiotibiales, luego empuja con los talones y activa los glúteos para volver a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Cadera atrás", "Espalda derecha", "Extiendo el glúteo hacia atrás con la espalda derecha"]'::jsonb, errores = '["Espalda redondeada", "Peso lejos del cuerpo", "Tirar con los brazos"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Menos peso o menos recorrido', progresion = 'Más peso o barra' WHERE lower(nombre) = lower('Peso muerto con kettlebell');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-trx.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Coloca un entrenador de suspensión o correas a la altura del pecho.", "Ponte de pie frente al punto de anclaje y agarra las asas con agarre prono.", "Camina con los pies hacia adelante, inclinándote hacia atrás hasta que el cuerpo quede en ángulo.", "Mantén el cuerpo recto y activa el core.", "Tira del pecho hacia las asas, apretando los omóplatos entre sí.", "Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo en TRX inclinado');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/puente-gluteos-peso.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Empieza tumbado boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo.", "Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos.", "Activa los glúteos y el core, luego levanta las caderas del suelo hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros.", "Haz una pausa breve en la parte alta, apretando los glúteos.", "Baja lentamente las caderas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Puente de gluteos con peso');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/sentadilla-barra.gif', musculo = 'quadriceps', secundarios = '["quadriceps", "hamstrings", "calves", "core"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera.", "Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores.", "Activa el core y mantén el pecho elevado mientras comienzas a bajar el cuerpo.", "Flexiona las rodillas y las caderas, empujando las caderas hacia atrás y hacia abajo como si te sentaras en una silla.", "Baja hasta que los muslos queden paralelos al suelo o un poco por debajo.", "Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones.", "Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Espalda derecha", "Peso en el talón, en la parte exterior", "Rodillas para afuera"]'::jsonb, errores = '["Rodillas hacia adentro", "Inclinarse mucho", "Perder postura"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Caja, TRX o menos peso', progresion = 'Más carga o variantes más exigentes' WHERE lower(nombre) = lower('Sentadilla con barra');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/peso-muerto-barra.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti.", "Flexiona las rodillas y las caderas para bajar el torso y agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros.", "Mantén la espalda recta y el pecho elevado mientras empujas con los talones para levantar la barra del suelo, extendiendo las caderas y las rodillas.", "Al ponerte de pie, aprieta los glúteos y mantén el core activado.", "Baja la barra de vuelta al suelo flexionando las caderas y las rodillas, manteniendo la espalda recta.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Barra pegada al cuerpo."]'::jsonb, errores = '["Redondear la espalda", "Tirar con los brazos", "Subir sin control"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Bloques o menos peso', progresion = 'Más carga' WHERE lower(nombre) = lower('Peso muerto con barra');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/dominadas.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Cuélgate de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos.", "Activa el core y junta los omóplatos.", "Tira de tu cuerpo hacia la barra flexionando los codos y llevando el pecho hacia la barra.", "Haz una pausa en la parte alta del movimiento y luego baja lentamente el cuerpo de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual', cues = '["Bajá los hombros."]'::jsonb, errores = '["Balancearse", "Subir con el cuello", "Soltarse rápido"]'::jsonb, red_flags = '[]'::jsonb, regresion = 'Con banda o TRX', progresion = 'Más repeticiones o lastre' WHERE lower(nombre) = lower('Dominadas');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/hip-thrust.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "core"]'::jsonb, instrucciones = '["Empieza sentado en el borde de un banco con la parte superior de la espalda apoyada contra él y los pies planos sobre el suelo, separados a la altura de las caderas.", "Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos.", "Activa los glúteos y el core, luego empuja con los talones para levantar las caderas del banco, creando una línea recta desde las rodillas hasta los hombros.", "Haz una pausa breve en la parte alta, apretando los glúteos.", "Baja lentamente las caderas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Hip thrust con barra o mancuerna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-un-brazo-banda.gif', musculo = 'biceps', secundarios = '["biceps", "shoulders"]'::jsonb, instrucciones = '["Sujeta la banda a un punto de anclaje estable a la altura de la cintura.", "Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros.", "Sostén la banda con una mano, con la palma hacia adentro, y da un paso atrás para generar tensión en la banda.", "Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta.", "Tira de la banda hacia la cintura, juntando los omóplatos.", "Haz una pausa por un momento en la parte superior del movimiento, luego suelta lentamente la banda de vuelta a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo con banda o polea baja');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/rotacion-externa-banda.gif', musculo = 'rotator cuff', secundarios = '["rotator cuff", "trapezius"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas.", "Sujeta el mango del cable con el brazo extendido frente a ti, paralelo al suelo.", "Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás.", "Rota lentamente el brazo hacia afuera, alejándolo de tu cuerpo, manteniendo el codo en la misma posición.", "Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Rotaciones externas con banda');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/push-up-pared.gif', musculo = 'triceps', secundarios = '["triceps", "deltoids"]'::jsonb, instrucciones = '["Ponte de pie frente a una pared, a una distancia aproximada de un brazo.", "Coloca las manos en la pared a la altura de los hombros, un poco más separadas que la anchura de los hombros.", "Da un paso atrás, manteniendo el cuerpo recto y los pies separados a la altura de las caderas.", "Flexiona los codos y baja el pecho hacia la pared, manteniendo el cuerpo en línea recta.", "Empuja de vuelta a la posición inicial, estirando los brazos.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Push-ups contra la pared');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/fuerza-impulso-barra.gif', musculo = 'triceps', secundarios = '["triceps", "core"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros.", "Flexiona ligeramente las rodillas y baja el cuerpo, luego extiende las piernas de forma explosiva y presiona las mancuernas por encima de la cabeza.", "Bloquea los brazos en la parte superior del movimiento, luego baja las mancuernas de vuelta a la altura de los hombros.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Fuerza con impulso con barra');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/press-pecho-barra.gif', musculo = 'triceps', secundarios = '["triceps", "shoulders"]'::jsonb, instrucciones = '["Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco.", "Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros.", "Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos.", "Baja la barra lentamente hacia el pecho, manteniendo los codos pegados al cuerpo.", "Haz una pausa breve cuando la barra toque el pecho.", "Empuja la barra de vuelta a la posición inicial extendiendo los brazos.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Pecho plano con barra');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/jalon-al-pecho.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Ajusta la máquina de jalón de cable de modo que el asiento quede a una altura cómoda y la almohadilla de rodillas esté asegurada.", "Siéntate con la espalda recta y los pies apoyados planos en el suelo.", "Sujeta la barra del cable con un agarre prono, un poco más separado que el ancho de los hombros.", "Inclínate ligeramente hacia atrás y activa el core.", "Jala la barra del cable hacia el pecho, apretando los omóplatos entre sí.", "Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Jalon al pecho / Maquina dorsales');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/hip-thrust.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "core"]'::jsonb, instrucciones = '["Empieza sentado en el borde de un banco con la parte superior de la espalda apoyada contra él y los pies planos sobre el suelo, separados a la altura de las caderas.", "Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos.", "Activa los glúteos y el core, luego empuja con los talones para levantar las caderas del banco, creando una línea recta desde las rodillas hasta los hombros.", "Haz una pausa breve en la parte alta, apretando los glúteos.", "Baja lentamente las caderas de vuelta a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Hip Thrust bilateral');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/fuerza-impulso-un-brazo.gif', musculo = 'triceps', secundarios = '["triceps", "core"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro.", "Flexiona ligeramente las rodillas y activa el core.", "Presiona la pesa rusa por encima de la cabeza extendiendo el brazo y estirando por completo las piernas.", "Baja la pesa rusa de vuelta a la posición inicial flexionando las rodillas y devolviendo la pesa rusa al hombro.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Fuerza con impulso a un brazo');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/zancada.gif', musculo = 'quadriceps', secundarios = '["quadriceps", "hamstrings", "calves"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano.", "Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada.", "Mantén la espalda recta y el pecho erguido mientras bajas el cuerpo.", "Empuja con el talón derecho para regresar a la posición inicial.", "Repite con la pierna izquierda.", "Alterna las piernas el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Zancada a una pierna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/pecho-inclinado-mancuerna.gif', musculo = 'shoulders', secundarios = '["shoulders", "triceps"]'::jsonb, instrucciones = '["Coloca un banco inclinado a un ángulo de 45 grados.", "Siéntate en el banco con los pies apoyados en el suelo y la espalda firmemente apoyada contra el banco.", "Sostén una mancuerna en cada mano, con las palmas hacia adelante, y levántalas hasta la altura de los hombros.", "Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángulo de 90 grados.", "Empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos.", "Repite el número de repeticiones deseado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Pecho inclinado con mancuerna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/peso-muerto-una-pierna.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "lower back"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha.", "Traslada tu peso a la pierna izquierda y levanta el pie derecho ligeramente del suelo.", "Manteniendo la espalda recta, inclínate hacia adelante desde las caderas y baja la mancuerna hacia el suelo.", "Al mismo tiempo, extiende la pierna derecha recta hacia atrás, manteniendo una ligera flexión en la rodilla izquierda.", "Baja la mancuerna hasta que tu torso y tu pierna derecha queden paralelos al suelo.", "Haz una pausa por un momento, luego activa los glúteos y los isquiotibiales para volver a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Peso muerto a una pierna');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/remo-un-brazo.gif', musculo = 'biceps', secundarios = '["biceps", "forearms"]'::jsonb, instrucciones = '["Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con la palma hacia el cuerpo.", "Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado.", "Deja que la mancuerna cuelgue recta hacia el suelo, con el brazo completamente extendido.", "Tira de la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo y juntando los omóplatos.", "Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de lado."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Remo a un brazo');
UPDATE biblioteca_ejercicios SET gif = '/ejercicios/levantada-cadera-una-pierna.gif', musculo = 'hamstrings', secundarios = '["hamstrings", "quadriceps"]'::jsonb, instrucciones = '["Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo.", "Extiende una pierna recta hacia delante.", "Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros.", "Mantén la posición alta por un momento, luego baja lentamente las caderas de nuevo a la posición inicial.", "Repite el número de repeticiones deseado, luego cambia de pierna."]'::jsonb, fuente_gif = 'gymvisual' WHERE lower(nombre) = lower('Levantada de cadera a una pierna');
INSERT INTO biblioteca_ejercicios (nombre, descripcion, video, gif, musculo, secundarios, instrucciones, fuente_gif) SELECT 'Farmer walk', 'Ponte de pie con una mancuerna en cada mano, palmas hacia los costados.', '', '/ejercicios/farmer-walk.gif', 'calves', '["calves", "forearms", "core"]'::jsonb, '["Ponte de pie con una mancuerna en cada mano, palmas hacia los costados.", "Mantén la espalda recta y los hombros hacia atrás.", "Da pasos pequeños y controlados hacia adelante, manteniendo una postura erguida.", "Continúa caminando durante la distancia o el tiempo deseado.", "Para terminar, deja de caminar y baja con cuidado las mancuernas a los costados."]'::jsonb, 'gymvisual' WHERE NOT EXISTS (SELECT 1 FROM biblioteca_ejercicios WHERE lower(nombre) = lower('Farmer walk'));
INSERT INTO biblioteca_ejercicios (nombre, descripcion, video, gif, musculo, secundarios, instrucciones, fuente_gif) SELECT 'Goblet squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa cerca del pecho con ambas manos.', '', '/ejercicios/goblet-squat.gif', 'quadriceps', '["quadriceps", "hamstrings", "calves"]'::jsonb, '["Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa cerca del pecho con ambas manos.", "Manteniendo el pecho elevado y el core activado, baja el cuerpo a una posición de sentadilla flexionando las rodillas y las caderas.", "Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente.", "Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial.", "Repite el número de repeticiones deseado."]'::jsonb, 'gymvisual' WHERE NOT EXISTS (SELECT 1 FROM biblioteca_ejercicios WHERE lower(nombre) = lower('Goblet squat'));

NOTIFY pgrst, 'reload schema';

-- Verificacion: cuantos ejercicios quedaron con gif y con cues
SELECT count(*) AS total, count(*) FILTER (WHERE gif <> '') AS con_gif, count(*) FILTER (WHERE cues <> '[]'::jsonb) AS con_cues FROM biblioteca_ejercicios;